	Describe(`GetContractTemplate(getContractTemplateOptions *GetContractTemplateOptions) - Operation response error`, func() {
		getContractTemplatePath := "/data_product_exchange/v1/contract_templates/testString"
		Context(`Using mock server endpoint with invalid JSON response`, func() {
			BeforeEach(func() {
				testServer = httptest.NewServer(http.HandlerFunc(func(res http.ResponseWriter, req *http.Request) {
					defer GinkgoRecover()

					// Verify the contents of the request
					Expect(req.URL.EscapedPath()).To(Equal(getContractTemplatePath))
					Expect(req.Method).To(Equal("GET"))
					Expect(req.URL.Query()["container.id"]).To(Equal([]string{"testString"}))
					res.Header().Set("Content-type", "application/json")
					res.WriteHeader(200)
					fmt.Fprint(res, `} this is not valid json {`)
				}))
			})
			It(`Invoke GetContractTemplate with error: Operation response processing error`, func() {
				dataProductHubAPIService, serviceErr := dataproducthubapiservicev1.NewDataProductHubAPIServiceV1(&dataproducthubapiservicev1.DataProductHubAPIServiceV1Options{
					URL:           testServer.URL,
					Authenticator: &core.NoAuthAuthenticator{},
				})
				Expect(serviceErr).To(BeNil())
				Expect(dataProductHubAPIService).ToNot(BeNil())

				// Construct an instance of the GetContractTemplateOptions model
				getContractTemplateOptionsModel := new(dataproducthubapiservicev1.GetContractTemplateOptions)
				getContractTemplateOptionsModel.ContractTemplateID = core.StringPtr("testString")
				getContractTemplateOptionsModel.ContainerID = core.StringPtr("testString")
				getContractTemplateOptionsModel.Headers = map[string]string{"x-custom-header": "x-custom-value"}
				// Expect response parsing to fail since we are receiving a text/plain response
				result, response, operationErr := dataProductHubAPIService.GetContractTemplate(getContractTemplateOptionsModel)
				Expect(operationErr).ToNot(BeNil())
				Expect(response).ToNot(BeNil())
				Expect(result).To(BeNil())

				// Enable retries and test again
				dataProductHubAPIService.EnableRetries(0, 0)
				result, response, operationErr = dataProductHubAPIService.GetContractTemplate(getContractTemplateOptionsModel)
				Expect(operationErr).ToNot(BeNil())
				Expect(response).ToNot(BeNil())
				Expect(result).To(BeNil())
			})
			AfterEach(func() {
				testServer.Close()
			})
		})
	})
